There is a miscompilation issue report in ValueTracking: 

```
#include "csmith.h"
uint32_t a;
int16_t c;
void d() {
  for (a = -15; a >= 6; a = safe_add_func_uint16_t_u_u(a, 9))
    ;
  c = safe_lshift_func_int16_t_s_u(safe_lshift_func_uint16_t_u_s(a,14), 0);
}
int main() {
  d();
  printf("%d\n", c);
  return 0;
}
```

```
dtcxzyw@dtcxzyw:~/WorkSpace/Projects/compilers/LLVM/llvm-build$ gcc -O0 test.c -fsanitize=undefined -I/usr/include/csmith -w
dtcxzyw@dtcxzyw:~/WorkSpace/Projects/compilers/LLVM/llvm-build$ ./a.out 
-16384
dtcxzyw@dtcxzyw:~/WorkSpace/Projects/compilers/LLVM/llvm-build$ bin/clang -O3 test.c -I/usr/include/csmith -w
dtcxzyw@dtcxzyw:~/WorkSpace/Projects/compilers/LLVM/llvm-build$ ./a.out 
0
```

llvm version: 2d6ff0c533aa1b0fe6d91764846f636c4a4e911c

The maintainers proposed the following patch to fix the issue:

commit 59eae919c938f890e9b9b4be8a3fa3cb1b11ed89
Author: Yingwei Zheng <dtcxzyw2333@gmail.com>
Date:   Wed Jul 24 20:06:36 2024 +0800

    [ValueTracking] Don't use CondContext in dataflow analysis of phi nodes (#100316)

    See the following case:
    ```
    define i16 @pr100298() {
    entry:
      br label %for.inc

    for.inc:
      %indvar = phi i32 [ -15, %entry ], [ %mask, %for.inc ]
      %add = add nsw i32 %indvar, 9
      %mask = and i32 %add, 65535
      %cmp1 = icmp ugt i32 %mask, 5
      br i1 %cmp1, label %for.inc, label %for.end

    for.end:
      %conv = trunc i32 %add to i16
      %cmp2 = icmp ugt i32 %mask, 3
      %shl = shl nuw i16 %conv, 14
      %res = select i1 %cmp2, i16 %conv, i16 %shl
      ret i16 %res
    }
    ```

    When computing knownbits of `%shl` with `%cmp2=false`, we cannot use
    this condition in the analysis of `%mask (%for.inc -> %for.inc)`.

    Fixes https://github.com/llvm/llvm-project/issues/100298.

diff --git a/llvm/include/llvm/Analysis/SimplifyQuery.h b/llvm/include/llvm/Analysis/SimplifyQuery.h
index a560744f0122..e8f43c8c2e91 100644
--- a/llvm/include/llvm/Analysis/SimplifyQuery.h
+++ b/llvm/include/llvm/Analysis/SimplifyQuery.h
@@ -130,6 +130,12 @@ struct SimplifyQuery {
     Copy.CC = &CC;
     return Copy;
   }
+
+  SimplifyQuery getWithoutCondContext() const {
+    SimplifyQuery Copy(*this);
+    Copy.CC = nullptr;
+    return Copy;
+  }
 };

 } // end namespace llvm
diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
